reg('baluster','architectural','Balustrade column shape',['baluster','railing'], (c,w,h) => pa(`M${w*0.35},${h*0.1} L${w*0.65},${h*0.1} Q${w*0.6},${h*0.3} ${w*0.55},${h*0.5} Q${w*0.6},${h*0.7} ${w*0.65},${h*0.9} L${w*0.35},${h*0.9} Q${w*0.4},${h*0.7} ${w*0.45},${h*0.5} Q${w*0.4},${h*0.3} ${w*0.35},${h*0.1}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))
reg('dentil','architectural','Dentil molding blocks',['dentil','classical'], (c,w,h) => { let s=''; for(let i=0;i<4;i++) s+=rc(i*w/3.5+w*0.05,h*0.3,w*0.2,h*0.4,c.color,c.opacity*0.1); return s })
reg('egg-and-dart','architectural','Egg and dart molding',['egg','classical'], (c,w,h) => `<ellipse cx="${w*0.25}" cy="${h*0.5}" rx="${w*0.15}" ry="${h*0.3}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.4}" opacity="${c.opacity*0.1}"/>` + pa(`M${w*0.6},${h*0.25} L${w*0.65},${h*0.75} L${w*0.7},${h*0.25}`,'none',c.color,c.strokeWidth*0.4,c.opacity*0.1))
reg('frieze-scroll','architectural','Scrolling frieze band',['frieze','scroll'], (c,w,h) => pa(`M0,${h*0.5} Q${w*0.15},${h*0.15} ${w*0.3},${h*0.3} Q${w*0.4},${h*0.5} ${w*0.3},${h*0.6} Q${w*0.2},${h*0.7} ${w*0.3},${h*0.8} Q${w*0.5},${h*0.9} ${w*0.6},${h*0.5} Q${w*0.7},${h*0.15} ${w*0.85},${h*0.3}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))
reg('pediment','architectural','Triangular pediment',['pediment','neoclassical'], (c,w,h) => pa(`M${w*0.05},${h*0.65} L${w*0.5},${h*0.15} L${w*0.95},${h*0.65} Z`,'none',c.color,c.strokeWidth,c.opacity*0.12))
reg('pagoda','architectural','Pagoda tiered roof',['pagoda','asian'], (c,w,h) => pa(`M${w*0.2},${h*0.7} Q${w*0.5},${h*0.5} ${w*0.8},${h*0.7} M${w*0.25},${h*0.5} Q${w*0.5},${h*0.3} ${w*0.75},${h*0.5} M${w*0.3},${h*0.3} Q${w*0.5},${h*0.1} ${w*0.7},${h*0.3}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.12))
reg('torii','architectural','Torii gate shape',['torii','japanese'], (c,w,h) => ln(w*0.2,h*0.3,w*0.8,h*0.3,c.color,c.strokeWidth*1.5,c.opacity*0.15) + ln(w*0.15,h*0.2,w*0.85,h*0.2,c.color,c.strokeWidth,c.opacity*0.12) + ln(w*0.3,h*0.3,w*0.3,h*0.9,c.color,c.strokeWidth,c.opacity*0.12) + ln(w*0.7,h*0.3,w*0.7,h*0.9,c.color,c.strokeWidth,c.opacity*0.12))
reg('minaret','architectural','Minaret silhouette',['minaret','islamic'], (c,w,h) => pa(`M${w*0.4},${h*0.9} L${w*0.4},${h*0.3} Q${w*0.4},${h*0.15} ${w*0.5},${h*0.08} Q${w*0.6},${h*0.15} ${w*0.6},${h*0.3} L${w*0.6},${h*0.9}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1) + ci(w*0.5,h*0.06,w*0.03,c.color,c.opacity*0.1))
reg('dome','architectural','Dome cupola shape',['dome','classical'], (c,w,h) => pa(`M${w*0.15},${h*0.7} Q${w*0.15},${h*0.2} ${w*0.5},${h*0.1} Q${w*0.85},${h*0.2} ${w*0.85},${h*0.7}`,'none',c.color,c.strokeWidth,c.opacity*0.12))
reg('flying-buttress','architectural','Flying buttress arc',['buttress','gothic'], (c,w,h) => pa(`M${w*0.1},${h*0.8} Q${w*0.3},${h*0.3} ${w*0.8},${h*0.15}`,'none',c.color,c.strokeWidth,c.opacity*0.12) + ln(w*0.8,h*0.15,w*0.8,h*0.8,c.color,c.strokeWidth*0.5,c.opacity*0.08))
reg('lancet','architectural','Lancet window narrow arch',['lancet','gothic'], (c,w,h) => pa(`M${w*0.3},${h*0.9} L${w*0.3},${h*0.35} Q${w*0.3},${h*0.05} ${w*0.5},${h*0.05} Q${w*0.7},${h*0.05} ${w*0.7},${h*0.35} L${w*0.7},${h*0.9}`,'none',c.color,c.strokeWidth,c.opacity*0.12))

// ═══ ISLAMIC (15) ═══
reg('star-8fold','islamic','Eight-pointed Islamic star',['star','geometric'], (c,w,h) => { const cx=w/2,cy=h/2,r=w*0.4; let d=''; for(let i=0;i<16;i++) { const a=i*Math.PI/8,ri=i%2===0?r:r*0.38; d+=(i===0?'M':'L')+`${cx+Math.cos(a)*ri},${cy+Math.sin(a)*ri} ` } return pa(d+'Z','none',c.color,c.strokeWidth*0.5,c.opacity*0.15) })
reg('star-12fold','islamic','Twelve-pointed star',['star','complex'], (c,w,h) => { const cx=w/2,cy=h/2,r=w*0.4; let d=''; for(let i=0;i<24;i++) { const a=i*Math.PI/12,ri=i%2===0?r:r*0.5; d+=(i===0?'M':'L')+`${cx+Math.cos(a)*ri},${cy+Math.sin(a)*ri} ` } return pa(d+'Z','none',c.color,c.strokeWidth*0.5,c.opacity*0.12) })
reg('arabesque-floral','islamic','Arabesque floral scroll',['arabesque','floral'], (c,w,h) => pa(`M0,${h/2} Q${w*0.2},${h*0.1} ${w*0.35},${h*0.3} Q${w*0.5},${h*0.5} ${w*0.5},${h*0.2} Q${w*0.5},0 ${w*0.65},${h*0.2} Q${w*0.8},${h*0.4} ${w},${h/2}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))
reg('girih','islamic','Girih strap pattern',['girih','strap'], (c,w,h) => { const cx=w/2,cy=h/2; let s=''; for(let i=0;i<5;i++) { const a1=i*TAU/5-Math.PI/2,a2=(i+2)*TAU/5-Math.PI/2,r2=w*0.4; s+=ln(cx+Math.cos(a1)*r2,cy+Math.sin(a1)*r2,cx+Math.cos(a2)*r2,cy+Math.sin(a2)*r2,c.color,c.strokeWidth*0.5,c.opacity*0.1) } return s })
reg('mashrabiya','islamic','Mashrabiya screen lattice',['mashrabiya','screen'], (c,w,h) => { const cx=w/2,cy=h/2,r=w*0.35; let s=`<circle cx="${cx}" cy="${cy}" r="${r}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.3}" opacity="${c.opacity*0.08}"/>`; for(let i=0;i<4;i++) { const a=i*Math.PI/2; s+=ln(cx,cy,cx+Math.cos(a)*r,cy+Math.sin(a)*r,c.color,c.strokeWidth*0.3,c.opacity*0.06) } return s })
reg('zellige-star','islamic','Zellige ceramic star tile',['zellige','moroccan'], (c,w,h) => { let s=''; for(let i=0;i<8;i++) { const a=i*Math.PI/4,r2=w*0.4; s+=ln(w/2,h/2,w/2+Math.cos(a)*r2,h/2+Math.sin(a)*r2,c.color,c.strokeWidth*0.5,c.opacity*0.08) } return s + `<circle cx="${w/2}" cy="${h/2}" r="${w*0.15}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.3}" opacity="${c.opacity*0.1}"/>` })
reg('rub-el-hizb','islamic','Rub el Hizb octagram',['octagram','quran'], (c,w,h) => { const cx=w/2,cy=h/2,r=w*0.35; return pa(`M${cx},${cy-r} L${cx+r*0.7},${cy} L${cx},${cy+r} L${cx-r*0.7},${cy} Z`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1) + pa(`M${cx-r},${cy} L${cx},${cy-r*0.7} L${cx+r},${cy} L${cx},${cy+r*0.7} Z`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1) })
reg('khatam','islamic','Khatam marquetry inlay',['khatam','persian'], (c,w,h) => { const s6=w/6; let s=''; for(let i=0;i<6;i++) { const a=i*Math.PI/3,r2=w*0.25; s+=`<polygon points="${w/2},${h/2} ${w/2+Math.cos(a)*r2},${h/2+Math.sin(a)*r2} ${w/2+Math.cos(a+Math.PI/3)*r2},${h/2+Math.sin(a+Math.PI/3)*r2}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.3}" opacity="${c.opacity*0.06}"/>` } return s })
reg('interlace-8','islamic','Eight-fold interlace knot',['interlace','knot'], (c,w,h) => { let s=''; for(let i=0;i<4;i++) { const a=i*Math.PI/4,r2=w*0.38,cx=w/2,cy=h/2; s+=pa(`M${cx+Math.cos(a)*r2},${cy+Math.sin(a)*r2} Q${cx},${cy} ${cx+Math.cos(a+Math.PI/2)*r2},${cy+Math.sin(a+Math.PI/2)*r2}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.08) } return s })
reg('rosette-islamic','islamic','Islamic rosette pattern',['rosette','geometric'], (c,w,h) => { let s=`<circle cx="${w/2}" cy="${h/2}" r="${w*0.15}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.3}" opacity="${c.opacity*0.1}"/>`; for(let i=0;i<12;i++) { const a=i*Math.PI/6,r2=w*0.35; s+=ci(w/2+Math.cos(a)*r2*0.5,h/2+Math.sin(a)*r2*0.5,w*0.03,'none',0) + `<circle cx="${w/2+Math.cos(a)*r2*0.5}" cy="${h/2+Math.sin(a)*r2*0.5}" r="${w*0.06}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.2}" opacity="${c.opacity*0.06}"/>` } return s })
reg('star-6fold','islamic','Six-pointed Islamic star',['star','hexagonal'], (c,w,h) => { const cx=w/2,cy=h/2,r=w*0.38; return pa(`M${cx},${cy-r} L${cx+r*0.87},${cy+r*0.5} L${cx-r*0.87},${cy+r*0.5} Z`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1) + pa(`M${cx},${cy+r} L${cx+r*0.87},${cy-r*0.5} L${cx-r*0.87},${cy-r*0.5} Z`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1) })
reg('arabesque-vine','islamic','Arabesque vine tendril',['arabesque','vine'], (c,w,h) => pa(`M0,${h} C${w*0.2},${h*0.3} ${w*0.4},${h*0.7} ${w*0.5},${h*0.3} C${w*0.6},0 ${w*0.8},${h*0.5} ${w},${h*0.1}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))
reg('muqarnas','islamic','Muqarnas honeycomb vault',['muqarnas','vault'], (c,w,h) => pa(`M0,${h} L${w*0.25},${h*0.5} L${w*0.5},${h} L${w*0.75},${h*0.5} L${w},${h} M${w*0.25},${h*0.5} L${w*0.5},0 L${w*0.75},${h*0.5}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))
reg('geometric-islam','islamic','Basic Islamic geometric',['geometric','tiling'], (c,w,h) => ln(0,h/2,w/2,0,c.color,c.strokeWidth*0.5,c.opacity*0.1) + ln(w/2,0,w,h/2,c.color,c.strokeWidth*0.5,c.opacity*0.1) + ln(w,h/2,w/2,h,c.color,c.strokeWidth*0.5,c.opacity*0.1) + ln(w/2,h,0,h/2,c.color,c.strokeWidth*0.5,c.opacity*0.1))
reg('biomorphic-islam','islamic','Biomorphic Islamic abstraction',['biomorphic','abstract'], (c,w,h) => pa(`M${w*0.5},${h*0.1} Q${w*0.9},${h*0.3} ${w*0.7},${h*0.6} Q${w*0.5},${h*0.9} ${w*0.3},${h*0.6} Q${w*0.1},${h*0.3} ${w*0.5},${h*0.1}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))

// ═══ MODERN (25) ═══
reg('memphis','modern','Memphis group design motif',['memphis','80s'], (c,w,h) => { const rng=seededRng(c.seed); return ci(rng()*w,rng()*h,w*0.08,c.color,c.opacity*0.1) + rc(rng()*w,rng()*h,w*0.15,h*0.03,c.color,c.opacity*0.08) + pa(`M${rng()*w},${rng()*h} L${rng()*w},${rng()*h} L${rng()*w},${rng()*h} Z`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.06) })
reg('glitch','modern','Digital glitch artifact',['glitch','digital'], (c,w,h) => { const rng=seededRng(c.seed); let s=''; for(let i=0;i<Math.ceil(c.density*6);i++) s+=rc(rng()*w*0.8,rng()*h,w*0.4+rng()*w*0.5,1+rng()*3,c.color,c.opacity*(0.03+rng()*0.08)); return s })
reg('pixel-art','modern','Pixel art grid cells',['pixel','retro'], (c,w,h) => { const rng=seededRng(c.seed),sz=Math.max(2,w/6); let s=''; for(let r=0;r<Math.ceil(h/sz);r++) for(let co=0;co<Math.ceil(w/sz);co++) if(rng()>0.6) s+=rc(co*sz,r*sz,sz-1,sz-1,c.color,c.opacity*(0.05+rng()*0.1)); return s })
reg('low-poly','modern','Low polygon faceted surface',['lowpoly','3d'], (c,w,h) => { const rng=seededRng(c.seed); let s=''; for(let i=0;i<4;i++) { const x1=rng()*w,y1=rng()*h,x2=rng()*w,y2=rng()*h,x3=rng()*w,y3=rng()*h; s+=pa(`M${x1},${y1} L${x2},${y2} L${x3},${y3} Z`,'none',c.color,c.strokeWidth*0.3,c.opacity*(0.04+rng()*0.08)) } return s })
reg('vaporwave','modern','Vaporwave retro grid',['vaporwave','aesthetic'], (c,w,h) => { let s=''; for(let i=0;i<=4;i++) { const y=h*0.4+i*h*0.15; s+=ln(0,y,w,y,c.color,c.strokeWidth*0.3,c.opacity*(0.03+i*0.02)) } for(let i=0;i<=5;i++) { const x=i*w/5; s+=ln(x,h*0.4,w/2+(x-w/2)*0.3,h,c.color,c.strokeWidth*0.3,c.opacity*0.05) } return s })
reg('neon-grid','modern','Neon wireframe grid',['neon','cyberpunk'], (c,w,h) => ln(0,0,w,0,c.color,c.strokeWidth*0.5,c.opacity*0.15) + ln(0,0,0,h,c.color,c.strokeWidth*0.5,c.opacity*0.15))
reg('wireframe-3d','modern','3D wireframe mesh',['wireframe','3d'], (c,w,h) => ln(0,h*0.6,w*0.5,h*0.3,c.color,c.strokeWidth*0.3,c.opacity*0.08) + ln(w*0.5,h*0.3,w,h*0.6,c.color,c.strokeWidth*0.3,c.opacity*0.08) + ln(w*0.5,h*0.3,w*0.5,0,c.color,c.strokeWidth*0.3,c.opacity*0.06) + ln(0,h*0.6,w,h*0.6,c.color,c.strokeWidth*0.3,c.opacity*0.06))
reg('moire','modern','Moiré interference pattern',['moire','optical'], (c,w,h) => { let s=''; for(let i=0;i<8;i++) { const r=w*0.05+i*w*0.05; s+=`<circle cx="${w/2}" cy="${h/2}" r="${r}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.3}" opacity="${c.opacity*0.04}"/>` } return s })
reg('op-art','modern','Op art optical illusion',['op-art','optical'], (c,w,h) => { let s=''; for(let i=0;i<6;i++) { const r=w*0.06+i*w*0.06; s+=`<rect x="${w/2-r}" y="${h/2-r}" width="${r*2}" height="${r*2}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.3}" opacity="${c.opacity*0.06}" transform="rotate(${i*7.5},${w/2},${h/2})"/>` } return s })
reg('de-stijl','modern','De Stijl neo-plastic grid',['destijl','mondrian'], (c,w,h) => ln(w*0.35,0,w*0.35,h,c.color,c.strokeWidth*1.5,c.opacity*0.15) + ln(0,h*0.6,w,h*0.6,c.color,c.strokeWidth*1.5,c.opacity*0.15) + rc(0,0,w*0.35,h*0.6,c.color,c.opacity*0.06))
reg('suprematist','modern','Suprematist abstract shape',['suprematist','abstract'], (c,w,h) => rc(w*0.2,h*0.3,w*0.4,h*0.15,c.color,c.opacity*0.08,0) + `<rect x="${w*0.4}" y="${h*0.5}" width="${w*0.35}" height="${h*0.25}" fill="${c.color}" opacity="${c.opacity*0.05}" transform="rotate(15,${w*0.575},${h*0.625})"/>`)
reg('constructivist','modern','Constructivist diagonal',['constructivist','russian'], (c,w,h) => pa(`M0,${h} L${w*0.7},0 L${w},0 L${w*0.3},${h} Z`,c.color,'none',0,c.opacity*0.06))
reg('escher-tessellation','modern','Escher-like interlocking',['escher','tessellation'], (c,w,h) => pa(`M0,${h*0.3} L${w*0.3},0 L${w*0.7},0 L${w},${h*0.3} L${w*0.7},${h*0.6} L${w},${h} L${w*0.6},${h} L${w*0.3},${h*0.6} L0,${h} Z`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))
reg('impossible-triangle','modern','Impossible Penrose triangle',['impossible','penrose'], (c,w,h) => pa(`M${w*0.5},${h*0.1} L${w*0.1},${h*0.85} L${w*0.9},${h*0.85} Z M${w*0.5},${h*0.3} L${w*0.25},${h*0.75} L${w*0.75},${h*0.75} Z`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))
reg('fractal-tree','modern','Fractal branching tree',['fractal','recursive'], (c,w,h) => { let s=ln(w/2,h,w/2,h*0.5,c.color,c.strokeWidth,c.opacity*0.12); s+=ln(w/2,h*0.5,w*0.3,h*0.25,c.color,c.strokeWidth*0.7,c.opacity*0.1); s+=ln(w/2,h*0.5,w*0.7,h*0.25,c.color,c.strokeWidth*0.7,c.opacity*0.1); s+=ln(w*0.3,h*0.25,w*0.15,h*0.1,c.color,c.strokeWidth*0.4,c.opacity*0.06); s+=ln(w*0.3,h*0.25,w*0.4,h*0.08,c.color,c.strokeWidth*0.4,c.opacity*0.06); s+=ln(w*0.7,h*0.25,w*0.6,h*0.08,c.color,c.strokeWidth*0.4,c.opacity*0.06); s+=ln(w*0.7,h*0.25,w*0.85,h*0.1,c.color,c.strokeWidth*0.4,c.opacity*0.06); return s })
reg('gradient-mesh','modern','Gradient mesh overlay',['gradient','mesh'], (c,w,h) => { let s=''; for(let i=0;i<=3;i++) for(let j=0;j<=3;j++) { s+=ci(i*w/3,j*h/3,w*0.02,c.color,c.opacity*0.05) } for(let i=0;i<3;i++) { s+=ln(i*w/3,0,i*w/3,h,c.color,c.strokeWidth*0.2,c.opacity*0.03); s+=ln(0,i*h/3,w,i*h/3,c.color,c.strokeWidth*0.2,c.opacity*0.03) } return s })
reg('retrowave','modern','Retrowave sunset grid',['retrowave','synthwave'], (c,w,h) => { let s=''; for(let i=0;i<5;i++) s+=ln(0,h*0.5+i*h*0.12,w,h*0.5+i*h*0.12,c.color,c.strokeWidth*0.3,c.opacity*(0.03+i*0.015)); for(let i=0;i<6;i++) { const x=i*w/5; s+=ln(x,h*0.5,w/2+(x-w/2)*0.2,h,c.color,c.strokeWidth*0.3,c.opacity*0.04) } return s + ci(w/2,h*0.3,w*0.15,c.color,c.opacity*0.04) })
reg('holographic','modern','Holographic rainbow stripe',['holographic','iridescent'], (c,w,h) => { let s=''; for(let i=0;i<8;i++) s+=rc(0,i*h/7,w,h/8,c.color,c.opacity*(0.01+Math.abs(Math.sin(i*0.7))*0.04)); return s })
reg('bauhaus-geo','modern','Bauhaus primary geometry',['bauhaus','geometric'], (c,w,h) => ci(w*0.25,h*0.5,w*0.18,c.color,c.opacity*0.08) + pa(`M${w*0.55},${h*0.2} L${w*0.95},${h*0.8} L${w*0.55},${h*0.8} Z`,c.color,'none',0,c.opacity*0.06))
reg('kinetic','modern','Kinetic art movement lines',['kinetic','motion'], (c,w,h) => { let s=''; for(let i=0;i<10;i++) { const x=w*(0.1+i*0.08),curve=Math.sin(i*0.5)*h*0.15; s+=pa(`M${x},0 Q${x+curve},${h/2} ${x},${h}`,'none',c.color,c.strokeWidth*0.3,c.opacity*(0.03+i*0.008)) } return s })
reg('data-viz','modern','Data visualization abstract',['data','abstract'], (c,w,h) => { let s=''; for(let i=0;i<5;i++) { const h1=(0.2+i*0.15)*h*c.density; s+=rc(i*w/5+1,h-h1,w/5-2,h1,c.color,c.opacity*(0.04+i*0.015)) } return s })
reg('circuit-modern','modern','Modern minimal circuit path',['circuit','minimal'], (c,w,h) => ln(0,h/2,w*0.3,h/2,c.color,c.strokeWidth*0.5,c.opacity*0.1) + ln(w*0.3,h/2,w*0.3,h*0.2,c.color,c.strokeWidth*0.5,c.opacity*0.1) + ln(w*0.3,h*0.2,w*0.7,h*0.2,c.color,c.strokeWidth*0.5,c.opacity*0.1) + ci(w*0.3,h/2,1.5,c.color,c.opacity*0.1) + ci(w*0.7,h*0.2,1.5,c.color,c.opacity*0.1))
reg('scanline','modern','CRT scanline overlay',['scanline','screen'], (c,w,h) => rc(0,0,w,1,c.color,c.opacity*0.04) + rc(0,h/2,w,1,c.color,c.opacity*0.04))
reg('dot-matrix-modern','modern','Modern dot matrix display',['dotmatrix','led'], (c,w,h) => { const cols=5,rows=3,gap=2; const cw=(w-gap*(cols+1))/cols,ch=(h-gap*(rows+1))/rows; let s=''; for(let r=0;r<rows;r++) for(let co=0;co<cols;co++) s+=ci(gap+co*(cw+gap)+cw/2,gap+r*(ch+gap)+ch/2,Math.min(cw,ch)*0.35,c.color,c.opacity*0.06); return s })

