reg('guilloche','decorative','Guilloche interlocking curves',['guilloche','security'], (c,w,h) => pa(`M0,${h/2} Q${w*0.25},${h*0.1} ${w*0.5},${h/2} Q${w*0.75},${h*0.9} ${w},${h/2}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.08) + pa(`M0,${h/2} Q${w*0.25},${h*0.9} ${w*0.5},${h/2} Q${w*0.75},${h*0.1} ${w},${h/2}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.08))
reg('scrollwork','decorative','Ornamental scroll curve',['scroll','ornamental'], (c,w,h) => pa(`M${w*0.1},${h/2} Q${w*0.2},${h*0.2} ${w*0.35},${h*0.35} Q${w*0.45},${h*0.45} ${w*0.35},${h*0.55} Q${w*0.2},${h*0.7} ${w*0.3},${h*0.8}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))
reg('medallion','decorative','Circular medallion motif',['medallion','ornate'], (c,w,h) => `<circle cx="${w/2}" cy="${h/2}" r="${w*0.35}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity*0.1}"/>` + `<circle cx="${w/2}" cy="${h/2}" r="${w*0.25}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.5}" opacity="${c.opacity*0.07}"/>` + `<circle cx="${w/2}" cy="${h/2}" r="${w*0.12}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.3}" opacity="${c.opacity*0.05}"/>`)
reg('festoon','decorative','Draped festoon swag',['festoon','swag'], (c,w,h) => pa(`M0,${h*0.2} Q${w*0.25},${h*0.7} ${w*0.5},${h*0.2} Q${w*0.75},${h*0.7} ${w},${h*0.2}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))
reg('ribbon','decorative','Ribbon bow motif',['ribbon','bow'], (c,w,h) => pa(`M${w*0.3},${h*0.5} Q${w*0.15},${h*0.3} ${w*0.25},${h*0.15} Q${w*0.4},${h*0.3} ${w*0.5},${h*0.45}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.08) + pa(`M${w*0.7},${h*0.5} Q${w*0.85},${h*0.3} ${w*0.75},${h*0.15} Q${w*0.6},${h*0.3} ${w*0.5},${h*0.45}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.08))
