reg('border-rope','decorative','Twisted rope border',['rope','border'], (c,w,h) => pa(`M0,${h*0.3} Q${w*0.15},${h*0.15} ${w*0.25},${h*0.35} Q${w*0.35},${h*0.55} ${w*0.5},${h*0.35} Q${w*0.65},${h*0.15} ${w*0.75},${h*0.35} Q${w*0.85},${h*0.55} ${w},${h*0.35}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))
