reg('corner-flourish','decorative','Corner flourish ornament',['corner','flourish'], (c,w,h) => pa(`M${w*0.05},${h*0.5} Q${w*0.05},${h*0.05} ${w*0.5},${h*0.05}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1) + pa(`M${w*0.15},${h*0.45} Q${w*0.12},${h*0.12} ${w*0.45},${h*0.15}`,'none',c.color,c.strokeWidth*0.3,c.opacity*0.06))
reg('filigree','decorative','Delicate filigree wirework',['filigree','delicate'], (c,w,h) => pa(`M${w*0.1},${h/2} Q${w*0.3},${h*0.2} ${w*0.5},${h/2} Q${w*0.7},${h*0.8} ${w*0.9},${h/2}`,'none',c.color,c.strokeWidth*0.3,c.opacity*0.08) + ci(w/2,h/2,w*0.03,c.color,c.opacity*0.06))
reg('damask-floral','decorative','Damask floral ornamental',['damask','floral'], (c,w,h) => pa(`M${w/2},${h*0.1} C${w*0.8},${h*0.15} ${w*0.85},${h*0.5} ${w/2},${h*0.55} C${w*0.15},${h*0.5} ${w*0.2},${h*0.15} ${w/2},${h*0.1}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.08) + pa(`M${w/2},${h*0.55} C${w*0.8},${h*0.6} ${w*0.85},${h*0.85} ${w/2},${h*0.9} C${w*0.15},${h*0.85} ${w*0.2},${h*0.6} ${w/2},${h*0.55}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.06))
reg('fleur-de-lis','decorative','Fleur-de-lis heraldic motif',['fleur','heraldic'], (c,w,h) => pa(`M${w*0.5},${h*0.1} Q${w*0.55},${h*0.3} ${w*0.7},${h*0.25} Q${w*0.65},${h*0.45} ${w*0.55},${h*0.5} L${w*0.55},${h*0.9} L${w*0.45},${h*0.9} L${w*0.45},${h*0.5} Q${w*0.35},${h*0.45} ${w*0.3},${h*0.25} Q${w*0.45},${h*0.3} ${w*0.5},${h*0.1}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.1))
reg('anthemion','decorative','Anthemion honeysuckle fan',['anthemion','greek'], (c,w,h) => { let s=''; for(let i=0;i<5;i++) { const a=-Math.PI/2+i*Math.PI/4-Math.PI/2,len=w*0.3; s+=pa(`M${w/2},${h*0.85} Q${w/2+Math.cos(a)*len*0.5},${h*0.4} ${w/2+Math.cos(a)*len},${h*0.15}`,'none',c.color,c.strokeWidth*0.3,c.opacity*0.06) } return s })
reg('trefoil','decorative','Three-lobed trefoil',['trefoil','gothic'], (c,w,h) => { const cx=w/2,cy=h/2,r=w*0.16; return `<circle cx="${cx}" cy="${cy-r*0.8}" r="${r}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.5}" opacity="${c.opacity*0.1}"/>` + `<circle cx="${cx+r*0.7}" cy="${cy+r*0.4}" r="${r}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.5}" opacity="${c.opacity*0.1}"/>` + `<circle cx="${cx-r*0.7}" cy="${cy+r*0.4}" r="${r}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.5}" opacity="${c.opacity*0.1}"/>` })
reg('cinquefoil','decorative','Five-lobed cinquefoil',['cinquefoil','heraldic'], (c,w,h) => { const cx=w/2,cy=h/2,r=w*0.13; let s=''; for(let i=0;i<5;i++) { const a=i*TAU/5-Math.PI/2; s+=`<circle cx="${cx+Math.cos(a)*r*0.9}" cy="${cy+Math.sin(a)*r*0.9}" r="${r}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.4}" opacity="${c.opacity*0.08}"/>` } return s })
reg('cartouche','decorative','Cartouche frame border',['cartouche','frame'], (c,w,h) => `<rect x="${w*0.1}" y="${h*0.15}" width="${w*0.8}" height="${h*0.7}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth}" opacity="${c.opacity*0.1}" rx="${w*0.08}"/>`)
reg('wreath','decorative','Laurel wreath circle',['wreath','laurel'], (c,w,h) => { const cx=w/2,cy=h/2,r=w*0.35; let s=''; for(let i=0;i<12;i++) { const a=i*TAU/12; s+=pa(`M${cx+Math.cos(a)*r*0.8},${cy+Math.sin(a)*r*0.8} Q${cx+Math.cos(a+0.2)*r},${cy+Math.sin(a+0.2)*r} ${cx+Math.cos(a+0.4)*r*0.8},${cy+Math.sin(a+0.4)*r*0.8}`,'none',c.color,c.strokeWidth*0.3,c.opacity*0.05) } return s })
reg('greek-wave','decorative','Greek wave running scroll',['greek','wave'], (c,w,h) => pa(`M0,${h*0.3} Q${w*0.15},${h*0.1} ${w*0.25},${h*0.3} Q${w*0.35},${h*0.5} ${w*0.25},${h*0.7} Q${w*0.15},${h*0.9} ${w*0.35},${h*0.7} L${w*0.5},${h*0.3} Q${w*0.65},${h*0.1} ${w*0.75},${h*0.3} Q${w*0.85},${h*0.5} ${w*0.75},${h*0.7} Q${w*0.65},${h*0.9} ${w*0.85},${h*0.7} L${w},${h*0.3}`,'none',c.color,c.strokeWidth*0.5,c.opacity*0.08))
reg('egg-dart-band','decorative','Egg and dart molding band',['egg-dart','molding'], (c,w,h) => { let s=''; for(let i=0;i<3;i++) { const x=i*w/2.5+w*0.1; s+=`<ellipse cx="${x}" cy="${h*0.5}" rx="${w*0.12}" ry="${h*0.3}" fill="none" stroke="${c.color}" stroke-width="${c.strokeWidth*0.3}" opacity="${c.opacity*0.08}"/>` } s+=pa(`M${w*0.4},${h*0.2} L${w*0.43},${h*0.8} L${w*0.46},${h*0.2}`,'none',c.color,c.strokeWidth*0.3,c.opacity*0.06); return s })

